  { "While", "while" },
  { "Break", "break" },
  { "Continue", "continue" },
  { "Const", "const" },
  { "Void", "void" },
};

void
print_token(const antlr4::Token* token,
            const antlr4::CommonTokenStream& tokens,
            std::ofstream& outFile,
            const antlr4::Lexer& lexer)
{
  auto& vocabulary = lexer.getVocabulary();

  auto tokenTypeName =
    std::string(vocabulary.getSymbolicName(token->getType()));

  if (tokenTypeName.empty())
    tokenTypeName = "<UNKNOWN>"; // 处理可能的空字符串情况

  // 跳过 LineAfterPreprocessing token
  if (tokenTypeName == "LineAfterPreprocessing") {
    return;
  }

  if (tokenTypeMapping.find(tokenTypeName) != tokenTypeMapping.end()) {
    tokenTypeName = tokenTypeMapping[tokenTypeName];
  }

  // 获取 token 在 token stream 中的索引
  size_t tokenIndex = token->getTokenIndex();

  // 检查是否是行首（StartOfLine）
  bool startOfLine = false;
  if (tokenIndex > 0) {
    auto prevToken = tokens.get(tokenIndex - 1);
    auto prevTokenType = std::string(vocabulary.getSymbolicName(prevToken->getType()));
    // 如果前一个 token 是换行符，或者这是第一个非空白 token
    if (prevTokenType == "Newline") {
      startOfLine = true;
    }
  } else {
    // 第一个 token
    startOfLine = true;
  }

  // 检查是否有前导空格（LeadingSpace）
  bool leadingSpace = false;
  if (tokenIndex > 0) {
    auto prevToken = tokens.get(tokenIndex - 1);
    auto prevTokenType = std::string(vocabulary.getSymbolicName(prevToken->getType()));
    // 如果前一个 token 是空白符
    if (prevTokenType == "Whitespace") {
      leadingSpace = true;
    }
  }

  // 构建位置信息
  std::string filename = currentFilename.empty() ? "<unknown>" : currentFilename;
  int line = token->getLine() + lineOffset;
  int col = token->getCharPositionInLine() + 1;
  std::string locInfo = " Loc=<" + filename + ":" + std::to_string(line) + ":" + std::to_string(col) + ">";

  if (token->getText() != "<EOF>")
    outFile << tokenTypeName << " '" << token->getText() << "'";
  else
    outFile << tokenTypeName << " '"
            << "'";
  if (startOfLine)
    outFile << "\t [StartOfLine]";
  if (leadingSpace)
    outFile << " [LeadingSpace]";
  outFile << locInfo << std::endl;
}

// 从预处理指令中提取文件名
// 格式: # linenum filename flags
void extractFilenameFromLine(const std::string& line) {
  // 匹配 # linenum "filename" 或 # linenum filename
  std::regex lineDirectiveRegex("^#\\s+(\\d+)\\s+\"([^\"]+)\".*");
  std::regex lineDirectiveRegex2("^#\\s+(\\d+)\\s+(\\S+).*");
  std::smatch match;

  if (std::regex_match(line, match, lineDirectiveRegex)) {
    lineOffset = std::stoi(match[1].str()) - 1;
    currentFilename = match[2].str();
  } else if (std::regex_match(line, match, lineDirectiveRegex2)) {
    lineOffset = std::stoi(match[1].str()) - 1;
    currentFilename = match[2].str();
  }
}

int
main(int argc, char* argv[])
{
  if (argc != 3) {
    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
    return -1;
  }

  std::ifstream inFile(argv[1]);
  if (!inFile) {
    std::cout << "Error: unable to open input file: " << argv[1] << '\n';
    return -2;
  }

  std::ofstream outFile(argv[2]);
  if (!outFile) {
    std::cout << "Error: unable to open output file: " << argv[2] << '\n';
    return -3;
  }

  std::cout << "程序 '" << argv[0] << std::endl;
  std::cout << "输入 '" << argv[1] << std::endl;
  std::cout << "输出 '" << argv[2] << std::endl;

  // 首先读取文件内容，提取预处理指令中的文件名
  std::string line;
  std::string fileContent;
  std::ifstream preprocessFile(argv[1]);
  while (std::getline(preprocessFile, line)) {
    // 检查是否是预处理指令行
    if (line.size() > 0 && line[0] == '#') {
      extractFilenameFromLine(line);
    }
  }
  preprocessFile.close();

  // 重新打开文件进行词法分析
  inFile.clear();
  inFile.seekg(0);

  antlr4::ANTLRInputStream input(inFile);
  SYsULexer lexer(&input);

  antlr4::CommonTokenStream tokens(&lexer);
  tokens.fill();

  for (auto&& token : tokens.getTokens()) {
    print_token(token, tokens, outFile, lexer);
  }
}

